/*
	将两个整数值互换
*/

#include <stdio.h>

/*--- 将px、py指向的对象的值进行互换 ---*/
void swap(int *px, int *py)
{
	int temp = *px;
	*px = *py;
	*py = temp;
}

int main(void)
{
	int na, nb;

	puts("请输入两个整数。");
	printf("整数A：");   scanf("%d", &na);
	printf("整数B：");   scanf("%d", &nb);

	swap(&na, &nb);

	puts("互换了两数的值。");
	printf("整数A是%d。\n", na);
	printf("整数B是%d。\n", nb);

	return 0;
}
所以,因为解引用的性质:在函数内完成了等效于在主调函数处做的事:
int temp = na;
na          = nb;
nb          = temp;

