                若*m == 12则 *d = 1;*m = 1;*y += 1;
                否则 *d == 31 ? *d = 1, *m += 1 : *d += 1
            小月则 *d == 30 ? *d = 1, *m += 1 : *d += 1
            闰月则 
                if(*d == 29)肯定是闰年
                {
                    *m += 1;
                    *d = 1;   
